/// <summary>
/// Calculates Gross Sales as SalesPrice multiplied by SalesQty.
/// </summary>
/// <returns>The gross sales amount.</returns>
[SysClientCacheDataMethod(true)]
public static server SalesAmount grossSales(SalesLine _salesLine)
{
    return _salesLine.SalesPrice * _salesLine.SalesQty;
}
